const binary = $binary ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function clampInt(value, fallback = 0, min = 0, max = 1000000) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function normalizeNumber(value, fallback = 0) {
  const number = Number(value);
  return Number.isFinite(number) ? number : fallback;
}

function safeJsonParse(value, fallback = null) {
  try {
    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function pickFirstString(candidates) {
  for (const candidate of candidates) {
    const text = String(candidate ?? '').trim();
    if (text) return text;
  }
  return '';
}

function resolveChunk(value) {
  if (value?.media_chunks && typeof value.media_chunks === 'object' && !Array.isArray(value.media_chunks)) {
    return value.media_chunks;
  }
  return value ?? {};
}

function readBinaryInfo(binaryMap) {
  const keys = Object.keys(binaryMap ?? {});
  if (keys.length === 0) {
    return {
      key: '',
      mimeType: '',
      fileName: '',
      bytes: 0,
      hasAudio: false,
      text: '',
      isBinaryReference: false,
    };
  }

  const key = keys.includes('tts_response') ? 'tts_response' : keys[0];
  const file = binaryMap[key] ?? {};
  const mimeType = safeText(file.mimeType);
  const bytes = clampInt(file.bytes, 0, 0, 1000000000);
  const contentRef = safeText(file.data);
  const isBinaryReference = contentRef === 'filesystem-v2' || contentRef.startsWith('filesystem-v2:');

  let text = '';
  if (!isBinaryReference && contentRef) {
    try {
      text = Buffer.from(contentRef, 'base64').toString('utf8');
    } catch (_) {
      text = '';
    }
  }

  return {
    key,
    mimeType,
    fileName: safeText(file.fileName),
    bytes,
    isBinaryReference,
    hasAudio: Boolean(key) && mimeType.toLowerCase().startsWith('audio/'),
    text,
  };
}

function parseResponsePayload(value, binaryInfo) {
  const candidates = [
    value?.body,
    value?.data,
    value?.payload,
    value?.result,
    value?.response,
    binaryInfo.text,
  ];

  for (const candidate of candidates) {
    const text = safeText(candidate);
    if (!text) continue;
    if (!text.startsWith('{') && !text.startsWith('[')) continue;
    const parsed = safeJsonParse(text, null);
    if (parsed) return parsed;
  }

  return null;
}

const chunk = resolveChunk(input);
const binaryInfo = readBinaryInfo(binary);
const parsed = parseResponsePayload(input, binaryInfo);
const headers = input.headers ?? input.responseHeaders ?? input?.response?.headers ?? {};
